import * as chai from 'chai';
import * as path from 'path';
let { expect } = chai;
let findRoot = require('find-root');

import Persistence from '../main/Persistence';


let ROOT = findRoot(module.filename);


function reset() {
  return Persistence._resetInstance();
}

describe('Main Test suite', () => {

  it('Loading library through main export', () => {
    let pack = require(path.join(ROOT, 'package.json'));
    let main = require(path.join(ROOT, pack.main));

    expect(main.default.prototype.constructor.name).to.equal('Persistence');
  });


  it('Getting data', (done) => {
    let p = reset();

    p.get('some-key')
    .then(node => {
      expect(node.key).to.equal('some-key');
      node.data.name = 'Bla';
      return node.save();
    }).then(() => {
      // Here we reset the storage (enforcing reloading from disk)
      p = reset();
      return p.get('some-key');
    }).then(node => {
      expect(node.key).to.equal('some-key');
      expect(node.data.name).to.equal('Bla');
      done();
    }).catch(done);
  });

});
